// Filter conversations updated within the lookback window.
// Output: one item per (account_id, conversation_id) pair.
const WINDOW_MS = 900 * 1000;
const ACCOUNT_ID = 1;
const cutoff = Math.floor((Date.now() - WINDOW_MS) / 1000);
const body = $input.first().json;
const convs = body.data?.payload || body.payload || [];
return convs
  .filter(c => (c.last_activity_at || 0) >= cutoff)
  .map(c => ({
    json: {
      account_id: c.account_id || ACCOUNT_ID,
      conversation_id: c.id,
      conversation_labels: c.labels || [],
      source_id: c.source_id || null,
    }
  }));

const WINDOW_MS = 900 * 1000;
const cutoff = Math.floor((Date.now() - WINDOW_MS) / 1000);
const labelsByConv = {};
for (const it of $('extract_recent_convs').all()) {
  labelsByConv[it.json.conversation_id] = it.json.conversation_labels || [];
}
const out = [];
for (const item of $input.all()) {
  const data = item.json;
  const messages = data.data?.payload || data.payload || [];
  for (const m of messages) {
    if (m.message_type !== 0) continue;
    const senderType = (m.sender_type || '').toLowerCase();
    if (senderType && senderType !== 'contact') continue;
    if ((m.created_at || 0) < cutoff) continue;
    if ((m.content_type || 'text') !== 'text') continue;
    if ((m.attachments || []).length > 0) continue;
    if (!m.content || !m.content.trim()) continue;
    out.push({
      json: {
        id: m.id,
        source_id: m.source_id || String(m.id),
        content: m.content,
        created_at: m.created_at,
        created_at_iso: new Date(m.created_at * 1000).toISOString(),
        account_id: m.account_id || 1,
        conversation_id: m.conversation_id,
        sender_phone: m.sender?.phone_number || m.sender?.identifier || '',
        sender_name: m.sender?.name || '',
        conversation_labels: labelsByConv[m.conversation_id] || [],
      }
    });
  }
}
return out;

const source = $('filter_inbound_recent').item.json;
const isProcessed = ($('check_dedup').item.json.is_processed || '').toString().trim();
const isQueued = ($('check_queued').item.json.is_queued || '').toString().trim();
if (isProcessed !== '' || isQueued !== '') {
  return { ...source, status: 'already_processed' };
}
const lastTsStr = ($json.last_ts || '').toString().trim();
const msgCreatedAt = Number(source.created_at) || 0;
let outOfOrder = false;
if (lastTsStr !== '') {
  let lastEpoch;
  if (/^\d+$/.test(lastTsStr)) {
    lastEpoch = Number(lastTsStr);
  } else {
    lastEpoch = Math.floor(new Date(lastTsStr).getTime() / 1000);
  }
  if (Number.isFinite(lastEpoch) && lastEpoch > msgCreatedAt) {
    outOfOrder = true;
  }
}
return { ...source, status: outOfOrder ? 'out_of_order' : 'in_order' };
